import React, { useState } from 'react';
import BoardCard from '../components/BoardCard';
import ArticleCard from '../components/ArticleCard';
import Button from '../components/Button';
import Modal from '../components/Modal';
import Input from '../components/Input';

const ClippingsPage = () => {
    const [activeBoard, setActiveBoard] = useState(null);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [newBoardTitle, setNewBoardTitle] = useState('');

    // Mock Data
    const [boards, setBoards] = useState([
        {
            id: 1,
            title: "Must Read",
            articles: [
                { id: 101, title: "The Future of AI", category: "Tech", imageUrl: "https://images.unsplash.com/photo-1677442136019-21780ecad995?auto=format&fit=crop&q=80&w=800" },
                { id: 102, title: "Climate Action Now", category: "Environment", imageUrl: "https://images.unsplash.com/photo-1621274790572-7c333acace02?auto=format&fit=crop&q=80&w=800" },
            ],
            previewImages: [
                "https://images.unsplash.com/photo-1677442136019-21780ecad995?auto=format&fit=crop&q=80&w=800",
                "https://images.unsplash.com/photo-1621274790572-7c333acace02?auto=format&fit=crop&q=80&w=800"
            ]
        },
        {
            id: 2,
            title: "Design Inspiration",
            articles: [
                { id: 201, title: "Minimalist Architecture", category: "Design", imageUrl: "https://images.unsplash.com/photo-1486718448742-163732cd1544?auto=format&fit=crop&q=80&w=800" },
            ],
            previewImages: [
                "https://images.unsplash.com/photo-1486718448742-163732cd1544?auto=format&fit=crop&q=80&w=800"
            ]
        },
        {
            id: 3,
            title: "Weekend Recipes",
            articles: [],
            previewImages: []
        }
    ]);

    const handleCreateBoard = () => {
        if (!newBoardTitle.trim()) return;

        const newBoard = {
            id: Date.now(),
            title: newBoardTitle,
            articles: [],
            previewImages: []
        };

        setBoards([...boards, newBoard]);
        setNewBoardTitle('');
        setIsModalOpen(false);
    };

    return (
        <div className="min-h-screen bg-cream-50 px-6 py-12">
            <div className="max-w-7xl mx-auto">

                {/* Header */}
                <div className="flex flex-col md:flex-row justify-between items-end mb-12 border-b-4 border-black pb-8">
                    <div>
                        <h1 className="font-serif text-4xl sm:text-5xl md:text-7xl font-black mb-2">
                            {activeBoard ? activeBoard.title : 'CLIPPINGS'}
                        </h1>
                        <p className="text-xl font-bold text-gray-500">
                            {activeBoard ? `${activeBoard.articles.length} Articles Saved` : 'Your personal collection of stories.'}
                        </p>
                    </div>

                    <div className="flex gap-4 mt-6 md:mt-0">
                        {activeBoard ? (
                            <Button onClick={() => setActiveBoard(null)} variant="outline">
                                ← BACK TO BOARDS
                            </Button>
                        ) : (
                            <Button onClick={() => setIsModalOpen(true)} variant="primary">
                                + NEW BOARD
                            </Button>
                        )}
                    </div>
                </div>

                {/* Content */}
                {activeBoard ? (
                    // Board View (Articles)
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 animate-fade-in">
                        {activeBoard.articles.length > 0 ? (
                            activeBoard.articles.map((article) => (
                                <ArticleCard
                                    key={article.id}
                                    title={article.title}
                                    category={article.category}
                                    imageUrl={article.imageUrl}
                                    size="small"
                                />
                            ))
                        ) : (
                            <div className="col-span-full text-center py-20">
                                <p className="text-2xl font-bold text-gray-400">No articles in this board yet.</p>
                                <Button variant="outline" className="mt-4">BROWSE HEADLINES</Button>
                            </div>
                        )}
                    </div>
                ) : (
                    // Overview (Boards Grid)
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 md:gap-8 animate-fade-in">
                        {boards.map((board) => (
                            <BoardCard
                                key={board.id}
                                title={board.title}
                                articleCount={board.articles.length}
                                previewImages={board.previewImages}
                                onClick={() => setActiveBoard(board)}
                            />
                        ))}

                        {/* Create New Board Card (Visual Shortcut) */}
                        <button
                            onClick={() => setIsModalOpen(true)}
                            className="group border-4 border-dashed border-gray-300 hover:border-soft-blue-400 bg-transparent h-full min-h-[300px] flex flex-col items-center justify-center transition-colors"
                        >
                            <span className="text-6xl text-gray-300 group-hover:text-soft-blue-400 mb-4">+</span>
                            <span className="font-bold text-xl text-gray-400 group-hover:text-soft-blue-500">CREATE NEW BOARD</span>
                        </button>
                    </div>
                )}

            </div>

            {/* Create Board Modal */}
            <Modal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                title="Create New Board"
                footer={
                    <>
                        <Button variant="outline" onClick={() => setIsModalOpen(false)}>CANCEL</Button>
                        <Button variant="primary" onClick={handleCreateBoard}>CREATE BOARD</Button>
                    </>
                }
            >
                <div className="space-y-4">
                    <p className="font-bold text-gray-600">Give your collection a name.</p>
                    <Input
                        placeholder="e.g., Tech Trends, Weekend Reads..."
                        value={newBoardTitle}
                        onChange={(e) => setNewBoardTitle(e.target.value)}
                        autoFocus
                    />
                </div>
            </Modal>

        </div>
    );
};

export default ClippingsPage;
